        density = self.stat == "density"
        hist, bin_edges = np.histogram(
            vals, **bin_kws, weights=weight, density=density,
        )

        width = np.diff(bin_edges)
        pos = bin_edges[:-1] + width / 2
        other = {"x": "y", "y": "x"}[orient]

